const order = $input.first().json.body || $input.first().json;
const items = order.items || [{ name: 'Product', qty: 1, price: order.total || 0 }];
const inventory = items.map(item => ({
  sku: item.sku || item.name,
  requested: item.qty || 1,
  inStock: true,
  available: 100
}));
const allInStock = inventory.every(i => i.inStock);

return [{
  json: {
    orderId: order.orderId || `ORD-${Date.now()}`,
    customerEmail: order.email || order.customerEmail || 'customer@example.com',
    customerName: order.customerName || 'Customer',
    items,
    inventory,
    allInStock,
    total: order.total || items.reduce((s, i) => s + (i.price || 0) * (i.qty || 1), 0)
  }
}];

const data = $input.first().json;
const invoiceNumber = `INV-${Date.now()}`;
return [{
  json: {
    ...data,
    invoiceNumber,
    invoiceDate: new Date().toISOString().split('T')[0],
    status: data.allInStock ? 'confirmed' : 'backorder',
    invoiceUrl: `https://invoices.example.com/${invoiceNumber}`
  }
}];

const data = $input.first().json;
return [{
  json: {
    ...data,
    emailSent: true,
    emailTo: data.customerEmail,
    emailSubject: `Order ${data.orderId} confirmed - Invoice ${data.invoiceNumber}`,
    emailBody: `Hi ${data.customerName}, your order of $${data.total} has been confirmed. Invoice: ${data.invoiceUrl}`
  }
}];
